  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

float corr = uTexSize.xy*texsize_noise_lq.zw;
vec2 uv1 = vec2(vUv.x-0.5,vUv.y-0.5)*uAspect.xy;

//vUv = vec2(vUv.x,vUv.y)*uAspect.xy;

ivec2 k1 = (uTexSize.xy*vUv)%2;

double3 ist = GetBlur1(vUv*1);

double3 crisp = texture(sampler_main,vUv);
crisp = crisp + (.03) -.01*pow(vRadius,2);

vec3 ret1 = crisp;

