void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    vec2 uv2, uv3;
    float ang2, c, s;

    vUv -= 0.5;
    vUv *= uAspect.xy;

vec3 ret1 = 0;
int anz = 6;
int n = 0;
while (n <= anz) {
    ang2 = 6.28*n/anz;
    c = cos(ang2);
    s = sin(ang2);
    uv2.x =  vUv.x*c - vUv.y*s;
